#include &lt;fcntl.h&gt;
#include &lt;stdio.h&gt;
#include &lt;unistd.h&gt;

// Elite standard: Never blindly overwrite flags. Always GET, then OR, then SET.
int make_socket_non_blocking(int fd) {
    // 1. Retrieve the existing flags from the OS
    int flags = fcntl(fd, F_GETFL, 0);
    if (flags == -1) {
        perror("fcntl F_GETFL failed");
        return -1;
    }

    // 2. Inject the Non-Blocking bit using Bitwise OR
    flags |= O_NONBLOCK; 

    // 3. Push the combined bitmask back to the OS
    if (fcntl(fd, F_SETFL, flags) == -1) {
        perror("fcntl F_SETFL failed");
        return -1;
    }

    return 0;
}

#include &lt;fcntl.h&gt;
#include &lt;stdio.h&gt;

int configure_server_socket(int fd) {
    // The engineer wants to ensure the socket is Non-Blocking
    // DANGER: They assign O_NONBLOCK directly to the File Descriptor flags
    if (fcntl(fd, F_SETFL, O_NONBLOCK) == -1) {
        perror("Failed to set non-blocking");
        return -1;
    }
    return 0;
}

#include &lt;stdio.h&gt;
#include &lt;errno.h&gt;
#include &lt;unistd.h&gt;
#include &lt;sys/socket.h&gt;

void service_client(int client_fd) {
    char buffer[1024];

    // Attempt to read. Because of O_NONBLOCK, this will NOT suspend the thread.
    ssize_t bytes = recv(client_fd, buffer, sizeof(buffer), 0);

    if (bytes < 0) {
        // The trap: We must distinguish between a 'try again' signal and a true crash.
        if (errno == EAGAIN || errno == EWOULDBLOCK) {
            // Expected behavior. No data is here yet.
            // We must return and let the server check other clients.
            // (In Day 44, we will learn how 'epoll' tells us exactly when to return here).
            return; 
        } else {
            // A real fatal network error occurred (e.g., ECONNRESET)
            perror("Fatal read error");
            close(client_fd);
        }
    } else if (bytes == 0) {
        // POSIX specification: 0 means the client disconnected gracefully.
        printf("Client disconnected.\n");
        close(client_fd);
    } else {
        // Data successfully processed!
        printf("Read %zd bytes.\n", bytes);
    }
}
